// Methodology — 20-module jury-report-based course. Generated file: replace methodology-data.js.
window.METHO = {"docs":{"article":{"kind":"Article · factual report","flag":"gb","title":"“2,800 jobs at risk as Tata announces Port Talbot Steelworks plans”","source":"Swansea Bay News / Tata Steel announcement","date":"January 2024","search":"https://www.google.com/search?q=Port+Talbot+Tata+Steel+blast+furnace+closure+jobs","gist":"A purely factual news report: Tata Steel will shut its blast furnaces at Port Talbot, putting up to 2,800 jobs at risk, and shift to a state-subsidised “green” electric arc furnace. No opinion is offered — the stake is for the reader to uncover."},"podcast":{"kind":"Podcast · audio analysis","flag":"us","title":"“The origins of ICE” — The Global Story (BBC World Service)","source":"BBC World Service, with Camilo Montoya-Galvez (CBS News)","date":"2026","search":"https://www.bbc.co.uk/sounds/search?q=the%20global%20story%20ICE","gist":"An audio episode tracing how ICE was created and why it became so controversial. The challenge: no re-reading — you must take notes, identify speakers, and follow an argument by ear."},"video":{"kind":"Video · editorial debate","flag":"gb","title":"“How special is Britain and America’s relationship?” — The Economist","source":"The Economist (Insider series)","date":"April 2026","search":"https://www.youtube.com/results?search_query=Economist+how+special+Britain+America+relationship","gist":"Editors debate why the transatlantic “special relationship” is fraying, with data and expert views. The challenge: analyse an argued discourse — thesis, evidence, standpoint."}},"modules":[{"id":"m0","n":"00","title":"Know What Your Exam Actually Requires","skill":"Format awareness","lead":"There is no universal oral format. Start by identifying the exact task, document type, preparation conditions and expected stages for the exam you are preparing.","lesson":[{"h":"What juries expect","p":"Candidates must answer the task that was actually set and respect the format of the target examination. The official notice, the latest jury report and your teacher's instructions take priority over habits learned for another competition."},{"h":"The common mistake","p":"Preparing a generic colle and assuming that every examination expects the same balance between restitution, commentary and discussion. A method that is appropriate for one competition may be incomplete or badly calibrated for another."},{"h":"A four-step format check","p":"Before practising, write down: 1) the document type; 2) the preparation conditions; 3) the stages expected during the oral; 4) what the examiner must still have time to assess during the exchange. Do not invent missing rules."},{"h":"Depends on your exam","p":"For example, CentraleSupélec uses recent written articles and limits the initial presentation; CCINP expects a longer continuous oral performance; Banque PT preserves a substantial interview; X/ENS uses a video and requires attention to both sound and images. BCE and e3a oral formats may depend on the school. Check the current official instructions."},{"h":"Do it yourself","p":"Create a one-page format card for the competition you are actually preparing. Include only verified information and the date of the source."},{"h":"Say it aloud","p":"Explain your target format in thirty seconds without reading: document, stages, and what the jury assesses."},{"h":"Use it in class or in your next colle","p":"Compare your format card with your teacher's instructions and correct any assumption that was not supported by an official source."},{"h":"Check what you can now do","p":"You can describe your target examination accurately and explain which parts of your usual colle method must be adapted."}],"filrouge":{"doc":"all","steps":[{"h":"One student, two different preparations","p":"A student preparing for CentraleSupélec must not copy a CCINP-style performance, and a student preparing for X/ENS must analyse visual choices that do not exist in a written article. The transferable skills remain the same; the format does not."}]},"dodont":[{"bad":"“A colle is always ten minutes of presentation followed by questions.”","good":"“My target exam requires these precise stages, according to the current official notice and jury report.”","why":"The first sentence turns one local habit into a universal rule. The second is verified and exam-specific."}],"exercises":[{"type":"qcm","intro":"Format first.","items":[{"q":"Before practising a target examination, what should you check first?","opts":["A universal timing chart","The current official format and your teacher's instructions","A memorised introduction","The longest possible presentation"],"c":1,"fb":"The task and current format determine the method."},{"q":"Which statement is safest?","opts":["All science competitions use the same oral","Every school in BCE and e3a uses one identical oral","Transferable skills exist, but formats must be checked separately","A normal classroom colle automatically matches every competition"],"c":2,"fb":"Skills transfer; formats and instructions may not."}]},{"type":"classify","intro":"Sort the statements.","binA":"Universal skill","binB":"Format-specific rule","items":[{"t":"Reformulate instead of paraphrasing","bin":"A"},{"t":"Analyse the images in a video","bin":"B"},{"t":"Use accurate examples","bin":"A"},{"t":"Follow the speaking stages required by one named competition","bin":"B"}]}]},{"id":"m1","n":"01","title":"Understand What Juries Really Assess","skill":"Assessment awareness","lead":"A strong performance combines comprehension, selection, analysis, language, delivery and interaction. Knowledge alone is not enough.","lesson":[{"h":"What juries expect","p":"Across competition reports, the recurring expectations are accurate comprehension, intelligent selection, reformulation, contextualisation, a relevant key question, a structured argument, precise examples, clear English, effective delivery and genuine interaction."},{"h":"The common mistake","p":"Trying to impress the jury by speaking for a long time, displaying prepared knowledge or using ambitious phrases that are not fully controlled."},{"h":"The assessment chain","p":"A useful way to understand the task is: understand → select → reformulate → contextualise → problematise → argue → communicate → interact. A weakness early in the chain affects everything that follows."},{"h":"Quality before display","p":"Juries repeatedly prefer clear, accurate and natural English to spectacular but incorrect language. A precise, well-explained example is more valuable than a list of references."},{"h":"Do it yourself","p":"After your next practice, identify one strength and one priority in each of three areas: ideas, language, and oral communication."},{"h":"Say it aloud","p":"State the main purpose of a colle in one sentence without using the words summary or knowledge."},{"h":"Use it in class or in your next colle","p":"Ask your teacher or colleur which link in the assessment chain currently limits your performance most."},{"h":"Check what you can now do","p":"You can explain why a knowledgeable candidate may still underperform and identify the specific skill that needs training."}],"filrouge":{"doc":"article","steps":[{"h":"Port Talbot through the assessment chain","p":"Understanding identifies the closure; selection keeps jobs, decarbonisation and public support; reformulation produces a concise account; contextualisation links the event to net zero and Welsh industrial decline; problematisation reveals the conflict between transition and community survival."}]},"dodont":[{"bad":"“I mentioned many facts, so my commentary was strong.”","good":"“I selected two accurate facts, explained their significance and linked them to my key question.”","why":"Assessment rewards analytical use, not accumulation."}],"exercises":[{"type":"match","intro":"Match each skill to its function.","items":[{"q":"Selection","opts":["Choose what is essential","Speak more quickly"],"c":0,"fb":"Selection reduces the document to what the audience needs."},{"q":"Contextualisation","opts":["Explain why the document matters now","List the country's entire history"],"c":0,"fb":"Context must serve this document."},{"q":"Interaction","opts":["Listen and develop an answer","Protect a memorised speech"],"c":0,"fb":"Interaction requires adaptation."}]},{"type":"qcm","intro":"Assessment judgement.","items":[{"q":"Which performance is strongest?","opts":["Long, ambitious and inaccurate","Short but entirely descriptive","Clear, structured, accurate and responsive","Full of memorised idioms"],"c":2,"fb":"Clarity, structure, accuracy and responsiveness are central."}]}]},{"id":"m2","n":"02","title":"Avoid the Main Jury-Report Traps","skill":"Error diagnosis","lead":"The most damaging weaknesses are recurrent: paraphrase, prepared material that does not fit, vague examples, artificial language, reading notes and weak interaction.","lesson":[{"h":"What juries repeatedly report","p":"The same problems appear across different competitions: linear restitution, lessons pasted onto the topic, inaccurate references, automatic pros-and-cons plans, basic language errors, excessive note reading and answers that do not engage with the examiner."},{"h":"The common mistake","p":"Treating these as isolated accidents rather than habits. A candidate who repeatedly paraphrases needs a different preparation action, not another reminder to 'analyse more'."},{"h":"Replace each trap with an action","p":"Paraphrase → name the stake. Prepared lecture → select one relevant fact and explain the link. Vague example → verify one precise example. Artificial English → simplify and correct. Reading → reduce notes to prompts. Weak interview → answer, justify and extend."},{"h":"The automatic-plan warning","p":"A plan based on advantages and disadvantages, for and against, or past-present-future is not automatically wrong, but it is usually too generic. The structure must come from the document's tension and the key question."},{"h":"Do it yourself","p":"Choose the two traps that appear most often in your feedback. Write one observable replacement behaviour for each."},{"h":"Say it aloud","p":"Reformulate one descriptive sentence into an analytical sentence beginning with This reveals… or This matters because…"},{"h":"Use it in class or in your next colle","p":"Ask a partner to stop you each time you paraphrase, list or read. Immediately replace the weak move with the analytical action you selected."},{"h":"Check what you can now do","p":"You can recognise a recurring jury-report trap in a concrete performance and prescribe a specific corrective action."}],"filrouge":{"doc":"video","steps":[{"h":"From description to analysis","p":"Weak: 'The video shows British and American flags and several politicians.' Better: 'The repeated official imagery reinforces the idea of a historic alliance, while the editors' disagreement exposes how fragile that narrative has become.'"}]},"dodont":[{"bad":"“Since the Industrial Revolution, Britain has always been an industrial country…”","good":"“Port Talbot matters because the closure turns Britain's net-zero strategy into a test of whether transition can protect industrial communities.”","why":"The first pastes a broad lesson onto the topic. The second selects and connects context."},{"bad":"“There are advantages and disadvantages.”","good":"“The policy promises environmental progress, but its local cost may undermine the political legitimacy of the transition.”","why":"The second sentence identifies a tension that can organise analysis."}],"exercises":[{"type":"classify","intro":"Identify the trap.","binA":"Jury-report trap","binB":"Corrective action","items":[{"t":"Repeat the document paragraph by paragraph","bin":"A"},{"t":"Name the underlying tension","bin":"B"},{"t":"Use an impressive quotation you cannot attribute","bin":"A"},{"t":"Verify one precise example and explain it","bin":"B"},{"t":"Read complete sentences from your notes","bin":"A"},{"t":"Use keywords as speaking prompts","bin":"B"}]},{"type":"spot","intro":"Spot the main weakness.","items":[{"q":"'The author says jobs will be lost. Then the author says the furnace will change. Then the union is angry.'","opts":["Strong prioritisation","Linear paraphrase","Precise contextualisation","Effective conclusion"],"c":1,"fb":"The response follows the document instead of reorganising it."},{"q":"'As Martin Luther King said, technology is always dangerous.'","opts":["Verified reference","Potentially invented or misattributed quotation","Strong transition","Neutral summary"],"c":1,"fb":"Never invent or guess a quotation."}]}]},{"id":"m3","n":"03","title":"Read Efficiently Without Translating Everything","skill":"Strategic reading","lead":"Read in several purposeful passes. Global meaning comes before isolated vocabulary.","lesson":[{"h":"What juries expect","p":"Candidates must understand and prioritise a recent document without turning preparation into word-by-word translation."},{"h":"The common mistake","p":"Spending too long on the first difficult sentence, copying complete passages, or treating every paragraph as equally important."},{"h":"First pass — frame the situation","p":"Use the title, subtitle, source, date, author, document type, first paragraph and final paragraph. Identify the country, actors, event and general topic."},{"h":"Second pass — map the structure","p":"Mark topic shifts, causes, consequences, oppositions, concessions, quotations, figures, repeated terms and logical connectors. Build the skeleton."},{"h":"Third pass — select evidence","p":"Return only to passages needed to verify an essential fact, understand a nuance or prepare the commentary."},{"h":"Do it yourself","p":"Take a current article and write a one-sentence situation after the first pass. Then draw its structure in no more than five notes."},{"h":"Say it aloud","p":"Explain the article's situation in two sentences without translating or quoting it."},{"h":"Use it in class or in your next colle","p":"During preparation, put a small mark beside any word that blocks an essential idea. Ignore words that do not block meaning."},{"h":"Check what you can now do","p":"You can reach a reliable global understanding before dealing with local difficulty."}],"filrouge":{"doc":"article","steps":[{"h":"First pass on Port Talbot","p":"Title, source and date identify a recent UK industrial announcement. The opening gives closure and job losses; the ending gives opposition. The situation is already clear."},{"h":"Second pass","p":"The figures show scale, the green furnace explains the transition, public funding raises responsibility, and union language introduces conflict."}]},"dodont":[{"bad":"Translate blast furnace before reading the rest.","good":"Infer an industrial installation from the closure and green-furnace context, then check only if the term matters later.","why":"Approximate meaning is often enough for the first pass."}],"exercises":[{"type":"qcm","intro":"Reading strategy.","items":[{"q":"What is the first-pass priority?","opts":["Translate every unfamiliar word","Identify the situation and document frame","Copy the first paragraph","Write the conclusion"],"c":1,"fb":"The first pass builds global understanding."},{"q":"When should you return to a difficult passage?","opts":["Always, immediately","Only if it affects an essential fact or nuance","Never","After memorising it"],"c":1,"fb":"Targeted rereading is more efficient."}]},{"type":"classify","intro":"What belongs in a second-pass structure map?","binA":"Useful structure signal","binB":"Usually secondary","items":[{"t":"However","bin":"A"},{"t":"A shift from causes to consequences","bin":"A"},{"t":"The journalist's middle initial","bin":"B"},{"t":"A repeated opposition between jobs and climate policy","bin":"A"},{"t":"The colour of a photograph","bin":"B"}]}]},{"id":"m4","n":"04","title":"Understand an Audio Document","skill":"Listening method","lead":"You will not catch every word. Listening succeeds when you capture situation, voices, structure and stakes.","lesson":[{"h":"What juries expect","p":"A structured account built from accurate listening, not a transcript or a pile of disconnected notes."},{"h":"The common mistake","p":"Trying to write every word, panicking after one missed phrase, or restarting the interpretation from zero at each listening."},{"h":"Before listening","p":"Use the title, source, date, programme, speaker information and likely context. Form hypotheses, but keep them provisional."},{"h":"First listening — big picture","p":"Identify who speaks, the main topic, the situation, the general tone and the main claim or concern."},{"h":"Second listening — structure","p":"Track voices, topic shifts, agreements, disagreements, causes, consequences, examples, figures and reformulations."},{"h":"Further listening, when allowed","p":"Check only what remains uncertain: a name, figure, chronology or nuance. Do not attempt a complete transcript."},{"h":"Do it yourself","p":"Listen to a short news segment and produce a speaker map plus a five-point structure."},{"h":"Say it aloud","p":"Give a neutral thirty-second account using your notes, then state the central tension separately."},{"h":"Use it in class or in your next colle","p":"Use columns for speakers and arrows for relationships. After the task, compare your structure with a partner's rather than comparing word counts."},{"h":"Check what you can now do","p":"You can miss individual words without losing the argument."}],"filrouge":{"doc":"podcast","steps":[{"h":"Before listening to the ICE podcast","p":"The BBC source, the title and the guest suggest a historical and political account of a US enforcement agency."},{"h":"First and second passes","p":"First identify host, expert, topic and analytical tone. Then map creation, expansion, controversy, evidence and competing views."}]},"dodont":[{"bad":"Write full sentences until you fall behind.","good":"Use ICE created → powers expand → security claim / civil-liberties criticism.","why":"The second note preserves the argument's structure."}],"exercises":[{"type":"order","intro":"Put the listening method in order.","scrambled":["Track structure and voices","Use the title and source to form hypotheses","Check only uncertain details","Identify the big picture"],"correct":[1,3,0,2],"fb":"Hypotheses → big picture → structure → targeted checking."},{"type":"match","intro":"Match the note tool to its use.","items":[{"q":"Columns","opts":["Separate speakers","Write a conclusion"],"c":0,"fb":"Columns prevent voices from being confused."},{"q":"Arrows","opts":["Show cause, consequence or opposition","Record spelling"],"c":0,"fb":"Arrows preserve relationships."},{"q":"Timeline","opts":["Order events","List adjectives"],"c":0,"fb":"A timeline clarifies chronology."}]}]},{"id":"m5","n":"05","title":"Analyse a Video as Sound and Image","skill":"Audiovisual analysis","lead":"A video is not an audio document with decoration. Images, editing, captions, setting and delivery contribute to meaning.","lesson":[{"h":"What juries expect","p":"Candidates should exploit the visual and auditory dimensions of the source, especially in video-based examinations."},{"h":"The common mistake","p":"Describing the sequence shot by shot or ignoring the images entirely while summarising only the spoken words."},{"h":"Read four layers","p":"Content: what is said. Delivery: tone, hesitation, emphasis. Image: setting, people, graphics, captions. Construction: cuts, sequencing, contrasts and source identity."},{"h":"Ask what the form does","p":"A visual detail matters only when you can explain its function: provide evidence, create authority, humanise an issue, dramatise conflict, simplify data or steer interpretation."},{"h":"Do it yourself","p":"Watch a short current-affairs video without sound, then with sound. List what each channel adds and where they contradict or reinforce each other."},{"h":"Say it aloud","p":"Explain one visual choice with the structure The video uses… in order to…, which reinforces/challenges…"},{"h":"Use it in class or in your next colle","p":"Include at least one analytically useful visual observation in your restitution or commentary, not a decorative description."},{"h":"Check what you can now do","p":"You can distinguish visual evidence from visual atmosphere and explain how the video constructs a viewpoint."}],"filrouge":{"doc":"video","steps":[{"h":"The special-relationship debate","p":"Official images of leaders and flags support the historic narrative, while the editors' disagreement, statistics and contrasting examples weaken the idea of an automatic alliance."}]},"dodont":[{"bad":"“We see flags, politicians and a studio.”","good":"“The repeated official imagery gives the alliance symbolic weight, but the argumentative editing exposes a widening gap between symbolism and national interest.”","why":"The effective version explains what the visuals do."}],"exercises":[{"type":"classify","intro":"Classify the observation.","binA":"Analytical visual evidence","binB":"Description only","items":[{"t":"A graph contradicts the speaker's optimistic claim","bin":"A"},{"t":"The presenter is wearing a blue jacket","bin":"B"},{"t":"Rapid cuts make the sequence feel urgent","bin":"A"},{"t":"There is a table in the studio","bin":"B"}]},{"type":"qcm","intro":"Video analysis.","items":[{"q":"When is a visual detail worth mentioning?","opts":["Whenever it is visible","When you can explain its function in the argument","Only when it is colourful","Never"],"c":1,"fb":"Function turns description into analysis."}]}]},{"id":"m6","n":"06","title":"Take Notes You Can Actually Speak From","skill":"Functional note-taking","lead":"Your notes must help you think and speak. They should not become a script that separates you from the examiner.","lesson":[{"h":"What juries expect","p":"A clear, communicative performance supported by notes rather than read from them."},{"h":"The common mistake","p":"Writing complete sentences during preparation, then reading them with little eye contact, flat intonation and no flexibility."},{"h":"Design speaking notes","p":"Use keywords, indentation, arrows, abbreviations, circles and white space. One visual block should correspond to one function or idea."},{"h":"Separate task stages","p":"Keep restitution facts, commentary ideas, examples and interview prompts visually distinct. This prevents repetition and helps you change register."},{"h":"The glance test","p":"A useful note should trigger an idea in one glance. If it requires silent reading, it is too long."},{"h":"Do it yourself","p":"Turn one paragraph of full notes into a half-page map with no complete sentence."},{"h":"Say it aloud","p":"Speak from the reduced map, then repeat with the paper placed farther away."},{"h":"Use it in class or in your next colle","p":"Mark every moment when you read more than a brief prompt. Reduce that section before the next attempt."},{"h":"Check what you can now do","p":"You can maintain eye contact, reformulate and answer an interruption without losing your structure."}],"filrouge":{"doc":"podcast","steps":[{"h":"A usable speaker map","p":"HOST: origins? → EXPERT: post-9/11 creation / expanded remit / controversy. EVIDENCE: cases + figures. TENSION: enforcement ↔ liberties. The map can be spoken from; a transcript cannot."}]},"dodont":[{"bad":"“The speaker then explains that the agency was created after…”","good":"creation → security context → remit expands → criticism","why":"The second version activates ideas instead of dictating sentences."}],"exercises":[{"type":"classify","intro":"Which notes are speakable?","binA":"Speaking prompt","binB":"Script-like note","items":[{"t":"jobs ↓ / green transition / union anger","bin":"A"},{"t":"The company has announced that it will close its blast furnaces.","bin":"B"},{"t":"WHY NOW? net zero + costs","bin":"A"},{"t":"In the first part of my commentary, I would like to explain…","bin":"B"}]},{"type":"qcm","intro":"The glance test.","items":[{"q":"A good speaking note should…","opts":["Contain elegant full sentences","Trigger the idea immediately","Include every detail","Be read word for word"],"c":1,"fb":"Notes are prompts, not a script."}]}]},{"id":"m7","n":"07","title":"Identify and Prioritise Essential Information","skill":"Selection and hierarchy","lead":"A strong account is built by deciding what the audience needs, not by preserving everything the document contains.","lesson":[{"h":"What juries expect","p":"Candidates should hierarchise information and avoid chronological or document-by-document dumping."},{"h":"The common mistake","p":"Keeping every figure, anecdote and quotation because it appears important on the page or was difficult to understand."},{"h":"Four information functions","p":"Essential: necessary to understand the situation. Supporting: explains or proves an essential point. Illustration: makes an idea concrete. Contextual: links the document to a wider situation."},{"h":"Make figures earn their place","p":"A figure is useful when it measures scale, change, inequality, contradiction or comparison. Its format alone does not make it essential."},{"h":"The deletion test","p":"Remove the item mentally. If the document's central meaning remains clear, the item may be secondary in the restitution, though it may still serve the commentary."},{"h":"Do it yourself","p":"Reduce fifteen notes to five points, then explain what function each surviving point performs."},{"h":"Say it aloud","p":"Give the account once with five points, then again with only three. Identify what cannot be removed."},{"h":"Use it in class or in your next colle","p":"Before speaking, label each note E, S, I or C. Do not give equal weight to all four categories."},{"h":"Check what you can now do","p":"You can justify why an item belongs in the account, commentary or nowhere."}],"filrouge":{"doc":"article","steps":[{"h":"Port Talbot hierarchy","p":"Essential: closure, jobs, green replacement, public support. Supporting: union reaction and cost arguments. Contextual: net zero and Welsh post-industrial decline. Incidental corporate detail can be removed."}]},"dodont":[{"bad":"Keep every number because statistics look serious.","good":"Keep 2,800 jobs because it measures social scale; omit figures that do not change the interpretation.","why":"Analytical function, not appearance, determines importance."}],"exercises":[{"type":"classify","intro":"For a concise account, sort the items.","binA":"Essential","binB":"Secondary","items":[{"t":"The furnaces will close","bin":"A"},{"t":"Thousands of jobs are at risk","bin":"A"},{"t":"The reporter's full biography","bin":"B"},{"t":"A passing description of the company logo","bin":"B"},{"t":"The switch to a lower-carbon furnace","bin":"A"}]},{"type":"qcm","intro":"Prioritising.","items":[{"q":"When is a statistic especially useful?","opts":["When it is long","When it demonstrates scale, change, inequality or contradiction","Whenever it includes a percentage","Only in the introduction"],"c":1,"fb":"A figure needs an analytical function."}]}]},{"id":"m8","n":"08","title":"Produce the Required Account, Summary or Restitution","skill":"Faithful reformulation","lead":"The label and exact task vary. In every case, identify what must remain neutral, what must be reorganised and how much detail the audience needs.","lesson":[{"h":"What juries expect","p":"A faithful, structured and reformulated account that demonstrates understanding. The exact meaning of summary, account, synthesis or restitution depends on the examination instructions."},{"h":"The common mistake","p":"Following the source paragraph by paragraph, mixing personal opinion into the account, or assuming that every task called summary requires the same product."},{"h":"Clarify the required product","p":"Ask: one document or several? neutral account or comparative synthesis? written or oral? Is the source structure useful, or must information be reorganised? What length or stage is explicitly required?"},{"h":"Reduce, regroup, reformulate","p":"Reduce secondary material. Regroup information that serves the same idea. Reformulate accurately in your own language without changing the source's degree of certainty."},{"h":"Neutral does not mean vague","p":"A neutral account can be precise about conflict, criticism and consequences. It simply avoids adding your own judgement."},{"h":"Do it yourself","p":"Write or deliver a compact account of a new document for a listener who has not seen it. Then underline every phrase copied too closely from the source."},{"h":"Say it aloud","p":"Give the same account in a shorter version while preserving actors, event, cause and stake."},{"h":"Use it in class or in your next colle","p":"Ask whether your account follows the source mechanically. Reorganise at least one section by importance or function."},{"h":"Check what you can now do","p":"You can produce the form of restitution required by your target task without confusing it with commentary."}],"filrouge":{"doc":"article","steps":[{"h":"A compact neutral account","p":"A major steelmaker will close its traditional furnaces, threatening thousands of jobs, and replace them with a lower-carbon facility supported by public funds; unions argue that the transition is unnecessarily destructive."}]},"dodont":[{"bad":"“Paragraph one says… paragraph two says…”","good":"Regroup closure, employment, transition and reaction into a meaningful sequence.","why":"The account follows ideas, not page order."},{"bad":"“This scandalous decision proves…”","good":"“Unions have condemned the decision as destructive.”","why":"The second reports a judgement without adopting it."}],"exercises":[{"type":"qcm","intro":"Account quality.","items":[{"q":"Which sentence belongs in a neutral account?","opts":["This disgraceful closure proves the company is greedy.","The company plans to close the furnaces, threatening thousands of jobs.","I strongly support the union.","The second paragraph is very interesting."],"c":1,"fb":"It is accurate, neutral and reformulated."},{"q":"Before producing an account, you should first…","opts":["Assume all summaries are identical","Clarify the exact product required by the task","Choose your personal opinion","Copy the source structure"],"c":1,"fb":"Task terms must be interpreted in context."}]},{"type":"order","intro":"Put the core process in order.","scrambled":["Reformulate accurately","Reduce secondary material","Regroup related information"],"correct":[1,2,0],"fb":"Reduce → regroup → reformulate."}]},{"id":"m9","n":"09","title":"Separate Restitution from Commentary","skill":"Task separation","lead":"The commentary must grow out of the document without repeating the account. It changes the question from what happened to what the document reveals.","lesson":[{"h":"What juries expect","p":"A clear distinction between faithful restitution and personal, argued commentary, especially in formats that explicitly require both stages."},{"h":"The common mistake","p":"Repeating the account with more adjectives, or beginning commentary with a prepared topic that has only a loose connection to the document."},{"h":"Change the intellectual task","p":"Restitution answers: what does the document say and how is it organised? Commentary answers: what tension, contradiction, transformation or wider stake does this case reveal?"},{"h":"Build a bridge","p":"Use one transition that names the issue: Beyond the immediate closure, the document raises a broader question about… This avoids both repetition and a disconnected jump."},{"h":"Control the overlap","p":"A fact may reappear in commentary only when its function changes: first reported, then interpreted as evidence for an argument."},{"h":"Do it yourself","p":"Take three facts from a document. Write one neutral restitution sentence and one analytical commentary sentence for each."},{"h":"Say it aloud","p":"Practise the transition from account to commentary until the change of purpose is audible and natural."},{"h":"Use it in class or in your next colle","p":"Draw a line on your notes between restitution and commentary. Circle any sentence that appears on both sides without a new analytical function."},{"h":"Check what you can now do","p":"You can explain the same fact first neutrally and then analytically without repetition."}],"filrouge":{"doc":"article","steps":[{"h":"Restitution","p":"Tata plans to replace the furnaces with a publicly supported lower-carbon facility, while thousands of jobs are threatened."},{"h":"Commentary","p":"The reliance on public funding makes the case a political test of who should bear the social cost of decarbonisation."}]},"dodont":[{"bad":"“As I said, jobs will be lost and the furnace will close.”","good":"“Beyond the closure itself, the case reveals how environmental policy can lose legitimacy when its costs are concentrated locally.”","why":"The effective transition changes from reporting to analysis."}],"exercises":[{"type":"classify","intro":"Restitution or commentary?","binA":"Restitution","binB":"Commentary","items":[{"t":"The agency was created in the post-9/11 security context.","bin":"A"},{"t":"Its expanding remit raises a conflict between security and civil liberties.","bin":"B"},{"t":"The video presents two editors with opposing interpretations.","bin":"A"},{"t":"Their disagreement suggests that the alliance no longer has one accepted meaning.","bin":"B"}]},{"type":"qcm","intro":"A fact may reappear in commentary when…","items":[{"q":"Choose the best rule.","opts":["It is repeated word for word","It now serves as evidence in an argument","The account was too short","You have no new idea"],"c":1,"fb":"Repetition becomes useful only when the function changes."}]}]},{"id":"m10","n":"10","title":"Identify the Real Issue","skill":"From topic to tension","lead":"A topic names the area. An issue identifies the conflict, contradiction or transformation that makes the document worth analysing.","lesson":[{"h":"What juries expect","p":"A commentary that moves beyond description and identifies what is genuinely at stake."},{"h":"The common mistake","p":"Calling immigration, technology, democracy or climate change the problem. These are themes, not analytical issues."},{"h":"Three levels","p":"Topic: industrial transition. Situation: a steelworks is closing during decarbonisation. Issue: can environmental transition protect the communities that bear its immediate cost?"},{"h":"Find resistance","p":"Ask what prevents a simple explanation or solution. Look for competing values, unequal costs, a gap between principle and practice, or an intended reform producing an unintended consequence."},{"h":"Write an issue sentence","p":"Use: The document raises the issue of… because… or The central tension lies between… and… This is not yet the final key question."},{"h":"Do it yourself","p":"For three current headlines, write the topic, situation and issue on separate lines."},{"h":"Say it aloud","p":"Explain the difference between the topic and issue of one document without notes."},{"h":"Use it in class or in your next colle","p":"Do not build a plan until you can state the issue in one precise sentence."},{"h":"Check what you can now do","p":"You can reject a broad theme and replace it with an analytical tension grounded in the document."}],"filrouge":{"doc":"all","steps":[{"h":"Port Talbot","p":"Topic: decarbonisation. Issue: environmental transition may deepen the insecurity of communities it is supposed to lead into a better future."},{"h":"ICE","p":"Topic: immigration enforcement. Issue: democratic states can expand coercive powers in the name of security while weakening civil liberties."}]},"dodont":[{"bad":"“The document is about climate change.”","good":"“The document exposes a conflict between national climate commitments and the local social cost of industrial transition.”","why":"The second sentence identifies the document's specific analytical problem."}],"exercises":[{"type":"qcm","intro":"Topic or real issue?","items":[{"q":"Which is a real issue?","opts":["Immigration","The United States","How enforcement can protect security while threatening civil liberties","A podcast"],"c":2,"fb":"It names a conflict that can organise analysis."},{"q":"What question helps reveal the issue?","opts":["How many paragraphs are there?","What prevents a simple explanation or solution?","Which word is longest?","Can I use my prepared plan?"],"c":1,"fb":"Resistance and conflict reveal the issue."}]},{"type":"spot","intro":"Spot the weakness.","items":[{"q":"'The main issue is technology.'","opts":["Too broad to analyse","Too precise","A complete key question","A useful example"],"c":0,"fb":"Technology is a theme, not a specific issue."}]}]},{"id":"m11","n":"11","title":"Contextualise Precisely","skill":"Relevant civilisation context","lead":"Context explains why this document appeared now and why it matters. Title, source and date are identification, not contextualisation.","lesson":[{"h":"What juries expect","p":"Relevant, accurate background knowledge that clarifies the document and is explicitly connected to it."},{"h":"The common mistake","p":"Historical dumping, decorative knowledge, vague claims about a country, or an introduction that gives only title, date and source."},{"h":"A five-step method","p":"1) Identify the immediate event. 2) Identify the broader debate. 3) Select one or two accurate civilisation facts. 4) explain the connection. 5) Stop before context overwhelms the document."},{"h":"Context is selective","p":"A true fact is not automatically relevant. It earns its place by helping the audience understand the actors, institution, timing, tension or consequences."},{"h":"Avoid country-as-character claims","p":"Do not write that Britain has always been pragmatic or Americans naturally value freedom. Name institutions, groups, historical developments and conflicts instead."},{"h":"Do it yourself","p":"Build context for a current document using no more than two background facts, and write one sentence explaining each connection."},{"h":"Say it aloud","p":"Deliver the context in under four clear sentences, without starting from centuries of history."},{"h":"Use it in class or in your next colle","p":"Ask your teacher whether each context sentence is necessary for understanding this document now."},{"h":"Check what you can now do","p":"You can distinguish relevant context from impressive but disconnected knowledge."}],"filrouge":{"doc":"article","steps":[{"h":"Port Talbot context","p":"Immediate event: the closure announcement. Broader debate: Britain's net-zero transition. Useful knowledge: Welsh post-industrial decline and the politics of a just transition. Connection: the plant concentrates a national dilemma in one community."}]},"dodont":[{"bad":"“Since the Industrial Revolution, Britain has had factories…”","good":"“The announcement comes as Britain tries to meet net-zero commitments while former industrial regions continue to experience economic insecurity.”","why":"The effective version selects context that explains the present conflict."}],"exercises":[{"type":"classify","intro":"Relevant context for Port Talbot?","binA":"Relevant","binB":"Off-topic or decorative","items":[{"t":"Britain's net-zero commitments","bin":"A"},{"t":"Post-industrial decline in parts of Wales","bin":"A"},{"t":"The history of the London Underground","bin":"B"},{"t":"The debate over a just transition","bin":"A"},{"t":"A complete chronology of every British government","bin":"B"}]},{"type":"order","intro":"Put the context method in order.","scrambled":["Explain the connection","Identify the broader debate","Stop before context dominates","Identify the immediate event","Select one or two facts"],"correct":[3,1,4,0,2],"fb":"Event → debate → facts → connection → stop."}]},{"id":"m12","n":"12","title":"Formulate a Strong Key Question","skill":"Problematisation","lead":"The key question must reveal a genuine tension and give the presentation a direction. It is not a rewritten title or an all-purpose formula.","lesson":[{"h":"What juries expect","p":"A clear, precise and document-based question that organises the commentary and can actually be answered by the plan."},{"h":"The common mistake","p":"Using To what extent automatically, asking a factual yes-or-no question, combining several questions, or writing an abstract formula that could fit any document."},{"h":"Build from the issue","p":"1) Name the specific situation. 2) Identify the tension. 3) identify the wider stake. 4) turn them into one analytical question."},{"h":"Test the question","p":"Can the answer be more than yes or no? Does every part of the plan answer it? Is it tied to this document? Can you understand it on first hearing?"},{"h":"Useful openings, not recipes","p":"How does this case reveal…? Why has… become…? What does the conflict between… and… reveal about…? Why does… remain difficult despite…?"},{"h":"Do it yourself","p":"Write three possible questions, then reject two using the four-part test."},{"h":"Say it aloud","p":"State the final question slowly and explain in one sentence why it matters."},{"h":"Use it in class or in your next colle","p":"Ask a partner to predict your plan from the question. If they cannot, make the question more directional."},{"h":"Check what you can now do","p":"You can turn a specific document tension into one focused analytical question without relying on To what extent."}],"filrouge":{"doc":"all","steps":[{"h":"Port Talbot","p":"Can a country decarbonise heavy industry without sacrificing the communities built around it?"},{"h":"ICE","p":"How can a democracy expand immigration enforcement without weakening the liberties it claims to protect?"},{"h":"The special relationship","p":"What does the growing gap between historic symbolism and national interest reveal about the future of the transatlantic alliance?"}]},"dodont":[{"bad":"“To what extent is ICE controversial?”","good":"“How can a democracy expand enforcement without weakening the liberties it claims to protect?”","why":"The effective version names a specific tension and wider stake."},{"bad":"“What is a steelworks?”","good":"“Can industrial transition remain politically legitimate when its costs fall on one community?”","why":"The first is factual; the second organises analysis."}],"exercises":[{"type":"qcm","intro":"Choose the strongest key question.","items":[{"q":"For the Port Talbot document:","opts":["What is Wales?","To what extent is industry good?","Can decarbonisation protect the communities that bear its immediate cost?","Are jobs important?"],"c":2,"fb":"It is precise, document-based and genuinely analytical."},{"q":"A strong key question should…","opts":["Contain several questions","Be reusable for every topic","Give the plan a direction","Have a yes-or-no answer"],"c":2,"fb":"The question structures the response."}]},{"type":"spot","intro":"Why is the question weak?","items":[{"q":"'How important is democracy and what are its advantages and disadvantages today?'","opts":["It is double, broad and generic","It is too factual","It is perfectly focused","It contains useful context"],"c":0,"fb":"One precise tension is needed."}]}]},{"id":"m13","n":"13","title":"Build a Plan That Answers the Question","skill":"Analytical organisation","lead":"A plan is a sequence of answers, not three boxes filled with everything you know.","lesson":[{"h":"What juries expect","p":"A clear progression in which every part answers the key question and develops the argument."},{"h":"The common mistake","p":"Automatic advantages/disadvantages, for/against, or past/present/future plans that do not emerge from the document's tension."},{"h":"Start with an answer","p":"Write a one-sentence provisional answer to the key question. The plan should explain, qualify and deepen that answer."},{"h":"Choose a progression","p":"Useful movements include appearance → limits → implications; principle → implementation → consequences; promise → contradiction → conditions for change. These are thinking patterns, not templates to paste."},{"h":"The part-title test","p":"Each part title must make a claim, not name a topic. 'Economic consequences' is weak; 'The transition concentrates its economic cost in already vulnerable communities' is argumentative."},{"h":"The evidence test","p":"Each part needs document evidence, precise external examples and an explicit link back to the question."},{"h":"Do it yourself","p":"Build two different plans for the same question, then choose the one with the clearest progression and least repetition."},{"h":"Say it aloud","p":"Announce the logic of your plan in natural language without saying first the advantages, then the disadvantages."},{"h":"Use it in class or in your next colle","p":"After speaking, ask whether each part changed or deepened the answer. Remove any part that merely repeats the topic."},{"h":"Check what you can now do","p":"You can produce a plan whose titles already answer the key question."}],"filrouge":{"doc":"article","steps":[{"h":"A possible progression","p":"I. Decarbonisation makes industrial transformation unavoidable. II. The current model places the social cost on one vulnerable community. III. A legitimate transition therefore depends on shared responsibility, retraining and regional investment."}]},"dodont":[{"bad":"I. Advantages of green industry. II. Disadvantages. III. My opinion.","good":"I. Necessity of transition. II. Unequal distribution of its cost. III. Conditions for a politically sustainable transition.","why":"The second plan follows the tension and builds an answer."}],"exercises":[{"type":"qcm","intro":"Plan judgement.","items":[{"q":"Which part title is most analytical?","opts":["History","Economic consequences","The policy shifts the cost of transition onto an already fragile region","Advantages"],"c":2,"fb":"It makes a claim that contributes to the answer."},{"q":"The first step in building a plan is to…","opts":["Choose three familiar topics","Write a provisional answer to the key question","Find an impressive quotation","Copy the source's paragraphs"],"c":1,"fb":"The answer determines the structure."}]},{"type":"classify","intro":"Does the title answer the question?","binA":"Argumentative title","binB":"Topic label","items":[{"t":"The alliance survives symbolically but weakens strategically","bin":"A"},{"t":"The United States","bin":"B"},{"t":"Enforcement gains power when political accountability is weak","bin":"A"},{"t":"Immigration","bin":"B"}]}]},{"id":"m14","n":"14","title":"Choose Accurate and Relevant Examples","skill":"Evidence selection","lead":"One verified and explained example is stronger than several vague references. Accuracy is part of the argument.","lesson":[{"h":"What juries expect","p":"Precise, relevant and factually reliable examples from the English-speaking world, used to support the point rather than decorate it."},{"h":"The common mistake","p":"Name-dropping, vague references to 'a law in America', invented quotations, approximate dates or examples that are never explained."},{"h":"The four-part example test","p":"Is it accurate? Is it relevant to this claim? Can you explain it in one or two sentences? Can you link it to the key question? If not, do not use it yet."},{"h":"Verify before reuse","p":"Use reliable news sources, official documents, your course and the CDI. Record the actor, date, event and significance. Never turn uncertain memory into a confident fact."},{"h":"Scale your example","p":"A law, election, court decision, social movement, company case or statistic can work. The example does not need to be famous; it needs to be exact and analytically useful."},{"h":"Do it yourself","p":"Build a verified example card with source, date, two facts, the claim it supports and one limitation."},{"h":"Say it aloud","p":"Present the example in twenty seconds, then add This matters because…"},{"h":"Use it in class or in your next colle","p":"Reuse one verified example and ask your teacher whether the explanation—not only the fact—supports your argument."},{"h":"Check what you can now do","p":"You can reject a vague or uncertain reference and replace it with evidence you can explain and defend."}],"filrouge":{"doc":"all","steps":[{"h":"Using an example analytically","p":"Do not merely mention the US Inflation Reduction Act. Identify the policy, explain how public subsidies aim to accelerate green industry, then compare the distribution of benefits and costs with the Port Talbot case."}]},"dodont":[{"bad":"“There was a similar thing in America.”","good":"“The US Inflation Reduction Act used large federal incentives to attract low-carbon investment, showing how industrial transition can be supported through public policy rather than left to one local employer.”","why":"The second example is identifiable and connected to the claim."},{"bad":"Quote a public figure from memory.","good":"Paraphrase the verified position or omit the quotation.","why":"A false quotation damages credibility."}],"exercises":[{"type":"qcm","intro":"The example test.","items":[{"q":"Which example is ready to use?","opts":["A law whose name and effect you only half remember","A verified case you can explain and connect to the argument","A quotation found on social media without a source","Three unrelated headlines"],"c":1,"fb":"Accuracy, explanation and relevance make evidence usable."},{"q":"What should you do with an uncertain quotation?","opts":["Make it sound confident","Attribute it to a famous person","Verify it or do not quote it","Translate it into French"],"c":2,"fb":"Never invent or guess a reference."}]},{"type":"classify","intro":"Example or name-drop?","binA":"Analytical example","binB":"Name-drop","items":[{"t":"Identify the policy, explain its effect and link it to the claim","bin":"A"},{"t":"Mention Brexit with no explanation","bin":"B"},{"t":"Use one verified court decision to demonstrate institutional conflict","bin":"A"},{"t":"List three presidents","bin":"B"}]}]},{"id":"m15","n":"15","title":"Explain Instead of Listing","skill":"Argument development","lead":"An argument is not a sequence of claims and examples. The essential work is explaining how the evidence proves the point and why the point matters.","lesson":[{"h":"What juries expect","p":"A developed line of reasoning with explicit links between claims, evidence and the key question."},{"h":"The common mistake","p":"Listing policies, people or consequences without showing relationships, or assuming that the example speaks for itself."},{"h":"Point → Evidence → Explanation → Link","p":"State a precise claim. Give evidence. Explain the mechanism or significance. Link the result to the key question or next stage of the argument."},{"h":"Use analytical verbs","p":"This reveals, demonstrates, illustrates, exposes, reinforces, challenges, complicates, results from, contributes to and depends on are useful only when the logic is genuine."},{"h":"Ask the mechanism question","p":"How does this happen? Who gains or loses? Through which institution? Under what condition? Compared with what? These questions turn a list into analysis."},{"h":"Do it yourself","p":"Take a paragraph from an old commentary. Label each sentence P, E, E or L. Add the missing function."},{"h":"Say it aloud","p":"Develop one point for forty-five seconds without introducing a second example until the first has been explained."},{"h":"Use it in class or in your next colle","p":"Ask your colleur to mark every unexplained example. Rewrite one passage using the four-part chain."},{"h":"Check what you can now do","p":"You can make the logical contribution of each fact explicit."}],"filrouge":{"doc":"article","steps":[{"h":"A developed argument","p":"Point: the transition's legitimacy depends on shared responsibility. Evidence: the new furnace receives substantial public support while workers face job losses. Explanation: public investment reduces corporate risk but does not automatically protect the local workforce. Link: decarbonisation may therefore fail politically unless social protection is part of the policy."}]},"dodont":[{"bad":"“There are job losses, public money, unions and climate targets.”","good":"“Because public money supports the technological shift without guaranteeing equivalent protection for workers, the policy appears to socialise investment while localising loss.”","why":"The effective sentence explains the relationship between the facts."}],"exercises":[{"type":"order","intro":"Build the argument chain.","scrambled":["Explain what the evidence shows","State the point","Link back to the key question","Provide accurate evidence"],"correct":[1,3,0,2],"fb":"Point → evidence → explanation → link."},{"type":"spot","intro":"What is missing?","items":[{"q":"'The Supreme Court made a major decision. This is a good example.'","opts":["A second court name","An explanation of what the decision demonstrates","More adjectives","A longer introduction"],"c":1,"fb":"The example needs an analytical function."}]}]},{"id":"m16","n":"16","title":"Use Civilisation Without Reciting a Lecture","skill":"Strategic background knowledge","lead":"Civilisation knowledge should clarify, compare and support. It should never replace the analysis of the document.","lesson":[{"h":"What juries expect","p":"Relevant knowledge of institutions, history and current debates, accurately selected and integrated into the argument."},{"h":"The common mistake","p":"Reciting a prepared chronology, using stereotypes, treating a country as a single personality or forcing a favourite example into every topic."},{"h":"Select, connect, explain","p":"Select one fact. State the precise connection to the document. Explain what the fact changes in the interpretation. Then return to the argument."},{"h":"Show internal diversity","p":"Name regions, institutions, parties, social groups and competing interpretations. Avoid claims such as Americans believe or Britain wants unless the actor is genuinely national and identified."},{"h":"Compare carefully","p":"A comparison must identify both a relevant similarity and a structural difference. Do not imply that two countries are interchangeable."},{"h":"Do it yourself","p":"Choose one civilisation fact from the site and write three lines: fact, connection, analytical use."},{"h":"Say it aloud","p":"Insert that fact into a commentary in under twenty seconds, then continue the argument without turning it into a lecture."},{"h":"Use it in class or in your next colle","p":"Ask whether the document would be less understandable without the fact. If not, remove or replace it."},{"h":"Check what you can now do","p":"You can use background knowledge as evidence or context rather than as a display of memory."}],"filrouge":{"doc":"article","steps":[{"h":"Wales as relevant context","p":"Mentioning Wales's industrial history is useful only when connected to current regional inequality, political identity and the social meaning of the closure. A chronology of British coal production is not needed."}]},"dodont":[{"bad":"“The British are pragmatic and have always led industrial change.”","good":"“In parts of Wales, deindustrialisation has already weakened employment and trust in national economic policy, which intensifies the political meaning of the closure.”","why":"The second sentence identifies a place, development and analytical connection without stereotyping."}],"exercises":[{"type":"classify","intro":"Useful civilisation or lecture dumping?","binA":"Useful","binB":"Dumping","items":[{"t":"One institutional fact that explains who can make the decision","bin":"A"},{"t":"A full chronology beginning centuries before the document","bin":"B"},{"t":"A comparison that names one similarity and one structural difference","bin":"A"},{"t":"A stereotype about an entire nation","bin":"B"}]},{"type":"qcm","intro":"The relevance test.","items":[{"q":"A civilisation fact should stay when…","opts":["It is impressive","You memorised it recently","It changes or clarifies the interpretation","It is very old"],"c":2,"fb":"Knowledge must do analytical work."}]}]},{"id":"m17","n":"17","title":"Build an Effective Introduction and Conclusion","skill":"Framing and closure","lead":"The introduction must orient the audience quickly. The conclusion must answer the question. Neither needs theatrical decoration.","lesson":[{"h":"What juries expect","p":"A clear opening that identifies and contextualises the document, presents the issue and establishes the analytical direction; a concise conclusion that answers the key question."},{"h":"The common mistake","p":"A memorised hook, excessive historical background, a mechanical announcement, or a conclusion that repeats the outline and adds a new undeveloped example."},{"h":"Build the introduction by function","p":"Identify the document and situation. Give necessary context. State the issue. Formulate the key question. Indicate the logic of the response when the format requires it."},{"h":"No mandatory hook","p":"A direct, precise first sentence is often stronger than a dramatic quotation or universal statement. Use an opening only when it genuinely frames the document."},{"h":"Build the conclusion","p":"Give a clear answer, name the main qualification or implication, and stop. An opening is optional and must grow naturally from the answer; it is not a compulsory extra topic."},{"h":"Do it yourself","p":"Write two introductions: one direct and one contextual. Keep the stronger one. Then reduce your conclusion to three functional sentences."},{"h":"Say it aloud","p":"Deliver the introduction without notes, then conclude when a partner interrupts with Please wrap up."},{"h":"Use it in class or in your next colle","p":"Ask whether your key question is audible and whether your conclusion actually answers it in the same terms."},{"h":"Check what you can now do","p":"You can frame and close the analysis without performance tricks or unnecessary material."}],"filrouge":{"doc":"article","steps":[{"h":"Direct introduction route","p":"A recent report on Port Talbot announces the closure of traditional steel furnaces and the loss of thousands of jobs during a publicly supported green transition. In a region already marked by deindustrialisation, the case raises a central question: can decarbonisation protect the communities that bear its immediate cost?"},{"h":"Concise conclusion","p":"Industrial transition is necessary, but it will remain politically fragile when investment support is separated from worker and regional protection. A credible just transition must distribute both costs and opportunities more fairly."}]},"dodont":[{"bad":"“Since the dawn of time, humanity has always needed progress…”","good":"Begin with the document, immediate event and relevant context.","why":"Generic drama delays the real subject."},{"bad":"Introduce a completely new example in the last sentence.","good":"Answer the question and state the main implication.","why":"A conclusion closes the reasoning; it does not begin another section."}],"exercises":[{"type":"order","intro":"A functional introduction.","scrambled":["State the key question","Identify the document and situation","Give relevant context","Name the issue"],"correct":[1,2,3,0],"fb":"Document and situation → context → issue → key question."},{"type":"spot","intro":"Spot the conclusion problem.","items":[{"q":"'To conclude, I have discussed jobs, climate and Wales. Another interesting topic is artificial intelligence.'","opts":["It answers the question clearly","It lists the outline and adds an unrelated opening","It is too contextualised","It uses too much evidence"],"c":1,"fb":"The conclusion must answer and close."}]}]},{"id":"m18","n":"18","title":"Speak Clearly Without Reading","skill":"Oral delivery","lead":"Communication depends on clear ideas, controlled language, audible structure and real contact with the examiner—not on sounding theatrical.","lesson":[{"h":"What juries expect","p":"Clear, correct and natural English; intelligible pronunciation; appropriate pace and emphasis; eye contact; and the ability to reformulate rather than read."},{"h":"The common mistake","p":"Writing a script, speaking too quickly to fit more content, using artificial idioms, or avoiding simple accurate language because it seems insufficiently impressive."},{"h":"Prioritise intelligibility","p":"Use shorter sentence units, stress key words, pause between ideas and pronounce essential names, figures and technical terms carefully."},{"h":"Use notes as prompts","p":"Look down to retrieve a keyword, then speak to the examiner. If a sentence is difficult to say naturally, simplify it rather than reading it."},{"h":"Self-correct productively","p":"Correct an error briefly when meaning or grammar matters, then continue. Repeated apologies and restarts disrupt communication more than a minor mistake."},{"h":"Natural language before display","p":"A controlled phrase such as This creates a conflict between… is stronger than an idiom you cannot explain or pronounce."},{"h":"Do it yourself","p":"Record one minute of your presentation. Count long reading episodes, unclear endings, rushed transitions and unnecessary filler."},{"h":"Say it aloud","p":"Repeat the passage with half the notes and one deliberate pause between each main idea."},{"h":"Use it in class or in your next colle","p":"Choose one delivery objective only—eye contact, sentence stress, pace or final consonants—and ask for observable feedback."},{"h":"Check what you can now do","p":"You can communicate a structured idea while adapting your wording in real time."}],"filrouge":{"doc":"all","steps":[{"h":"Speaking from structure","p":"Instead of reading a polished paragraph, use four prompts: claim / evidence / why / link. The wording can change while the reasoning remains stable."}]},"dodont":[{"bad":"Deliver a dense memorised sentence at speed.","good":"Divide the idea into two clear sentences, stress the contrast and pause before the implication.","why":"Intelligibility and control support analysis."}],"exercises":[{"type":"qcm","intro":"Oral delivery.","items":[{"q":"What should you do with a sentence you cannot say naturally?","opts":["Read it faster","Simplify and reformulate it","Apologise repeatedly","Skip the idea"],"c":1,"fb":"Controlled reformulation is a core oral skill."},{"q":"A useful self-correction is…","opts":["Brief and followed by continuation","A complete restart of the presentation","Impossible without notes","Always unnecessary"],"c":0,"fb":"Correct, then keep communicating."}]},{"type":"classify","intro":"Supports communication or blocks it?","binA":"Supports communication","binB":"Blocks communication","items":[{"t":"Pause between two major ideas","bin":"A"},{"t":"Read complete paragraphs","bin":"B"},{"t":"Stress the contrast in the key sentence","bin":"A"},{"t":"Use an idiom you cannot explain","bin":"B"}]}]},{"id":"m19","n":"19","title":"Handle the Interview and Turn Feedback into Action","skill":"Interaction and improvement","lead":"The interview is not an obstacle after the presentation. It is a second opportunity to think, clarify, defend and improve your answer.","lesson":[{"h":"What juries expect","p":"Candidates should listen, respond directly, develop answers, use prompts constructively, show intellectual flexibility and communicate even when uncertain."},{"h":"The common mistake","p":"Giving yes-or-no answers, repeating the presentation, defending every statement rigidly, or treating a prompt as proof that the performance has failed."},{"h":"A response sequence","p":"Listen to the full question. Identify its focus. Answer directly. Give a reason or example. Add a qualification or consequence. Stop and allow the examiner to continue."},{"h":"Clarify naturally","p":"Use Could you repeat the last part? Do you mean…? or Are you asking about the policy itself or its consequences? Clarification is better than answering a different question."},{"h":"Use prompts","p":"If the examiner suggests a counterexample or distinction, engage with it: That complicates my argument because… or I would revise my earlier claim in this way…"},{"h":"Handle uncertainty","p":"Do not invent. State what you know, mark the limit and reason carefully: I cannot recall the exact figure, but the broader trend is…"},{"h":"Turn feedback into action","p":"Rewrite broad comments as trainable objectives. 'Too descriptive' becomes 'After every factual point, add what it reveals.' 'I read my notes' becomes 'Use no complete sentences in the next plan.'"},{"h":"Do it yourself","p":"Choose one recent teacher or colleur comment. Define the behaviour to change, one exercise, one place to reuse it and one sign of improvement."},{"h":"Say it aloud","p":"Practise three interview moves: direct answer, respectful clarification and revision after a counterargument."},{"h":"Use it in class or in your next colle","p":"Ask your examiner for one priority only. Apply it in the next English class and the next colle, then report what changed."},{"h":"Check what you can now do","p":"You can respond rather than recite and convert feedback into a specific learning mission."}],"filrouge":{"doc":"all","steps":[{"h":"Using a challenge","p":"Examiner: 'But could public support protect both the company and the workers?' Weak: 'Yes, maybe.' Effective: 'Yes, but only if support is conditional. Funding technology without retraining or regional investment protects production capacity more than the community.'"},{"h":"From feedback to action","p":"Feedback: 'Your examples are vague.' Action: prepare one verified example card, use it orally in class, and ask whether the link to the claim is explicit."}]},"dodont":[{"bad":"Answer a difficult question with a long version of your prepared paragraph.","good":"Answer the precise focus, justify it, qualify it and stop.","why":"Interaction requires listening and adaptation."},{"bad":"“I am bad at methodology.”","good":"“My restitution is too linear; in the next task I will regroup information by function.”","why":"The second statement creates a trainable action."}],"exercises":[{"type":"order","intro":"Build an interview answer.","scrambled":["Add a reason or example","Listen to the whole question","Answer directly","Add a qualification if useful"],"correct":[1,2,0,3],"fb":"Listen → direct answer → support → qualification."},{"type":"qcm","intro":"Interview judgement.","items":[{"q":"What should you do when you do not remember an exact figure?","opts":["Invent a plausible number","Avoid answering","State the limit and reason from what you know","Blame the question"],"c":2,"fb":"Honest limits preserve credibility."},{"q":"Which is a useful feedback objective?","opts":["Be better at English","Use more impressive words","After each factual point, explain what it reveals","Never make mistakes"],"c":2,"fb":"It is observable and trainable."}]}]}],"closing":{"title":"The real training ground is the classroom and the colle","p1":"This course gives you a method, guided practice and tools. It does not replace English lessons, regular colles or precise feedback from a teacher. The decisive step is to reuse each skill aloud, under real conditions, and correct it with another person.","p2":"Use the site to prepare independently, then bring the result into class and into your next colle. A method becomes reliable only when you can adapt it to a new document, a new question and the exact format you are preparing."},"diagnostic":{"intro":"Quick self-check: select the statements that describe your current difficulty. The result suggests a starting point; it does not assign a level or replace feedback from your teacher or colleur.","items":[{"t":"I am not sure what my target exam actually requires.","mods":["m0"]},{"t":"I understand the topic but do not know what juries assess.","mods":["m1"]},{"t":"My feedback often mentions paraphrase, prepared material or vague examples.","mods":["m2"]},{"t":"I translate too much when reading.","mods":["m3"]},{"t":"I lose the structure of an audio document.","mods":["m4","m6"]},{"t":"I describe a video but do not analyse its images.","mods":["m5"]},{"t":"My notes are too long and I read them.","mods":["m6","m18"]},{"t":"I do not know what information to keep.","mods":["m7"]},{"t":"My account or summary is too linear or includes opinion.","mods":["m8"]},{"t":"My commentary repeats my restitution.","mods":["m9"]},{"t":"I identify a topic but not the real issue.","mods":["m10"]},{"t":"My introduction lacks relevant context.","mods":["m11","m17"]},{"t":"My key question is broad, factual or based on 'To what extent'.","mods":["m12"]},{"t":"I build automatic pros-and-cons plans.","mods":["m13"]},{"t":"My examples are vague, inaccurate or unexplained.","mods":["m14","m15"]},{"t":"I recite civilisation knowledge instead of using it.","mods":["m16"]},{"t":"My introduction or conclusion feels mechanical.","mods":["m17"]},{"t":"I speak from a script or use artificial language.","mods":["m18"]},{"t":"I give short answers or panic during the interview.","mods":["m19"]},{"t":"I receive feedback but do not know how to act on it.","mods":["m19"]}]},"tools":{"context_builder":{"title":"The Context Builder","intro":"Use these fields to build relevant context. The tool does not write your introduction for you: you must decide what is accurate, necessary and connected to the document.","fields":[{"k":"country","label":"Country / region","ph":"e.g. Wales, United Kingdom"},{"k":"actor","label":"Institution or group","ph":"e.g. Tata Steel, trade unions, the UK government"},{"k":"event","label":"Immediate event","ph":"e.g. the announced closure of the blast furnaces"},{"k":"issue","label":"Broader debate","ph":"e.g. industrial decarbonisation and a just transition"},{"k":"fact","label":"One accurate civilisation fact","ph":"e.g. long-term post-industrial decline in parts of Wales"},{"k":"link","label":"Why it helps explain this document","ph":"e.g. it intensifies the social and political meaning of the closure"}],"template":"This document concerns {actor} in {country}. It appeared in the immediate context of {event} and belongs to the wider debate on {issue}. The fact that {fact} helps explain why {link}."},"key_question_workshop":{"title":"The Key Question Workshop","intro":"Build one precise analytical question. The workshop guides your reasoning but does not generate the question for you. 'To what extent' is not accepted as an automatic formula.","steps":[{"k":"topic","label":"Step 1 — Specific situation","ph":"What is happening in this document?"},{"k":"tension","label":"Step 2 — Tension","ph":"Which values, interests, effects or claims conflict?"},{"k":"stakes","label":"Step 3 — Wider stake","ph":"Why does this conflict matter beyond the immediate case?"},{"k":"question","label":"Step 4 — One key question","ph":"Write one clear question that your plan can answer."}],"tensions":["Promise vs outcome","Rights vs enforcement","National interest vs shared values","Progress vs unequal cost","Political principle vs implementation","Unity vs regional difference","Security vs liberty","Growth vs sustainability"],"openers":["How does this case reveal…?","Why has… become…?","What does the conflict between… and… reveal about…?","Why does… remain difficult despite…?","How is… reshaping…?","Under what conditions can…?"]},"simulator":{"title":"Full colle simulator","intro":"Practise the complete method on a new document and adapt it to your target format. Your notes are stored locally in this browser only.","steps":[{"k":"format","label":"1 — Confirm the target format","ph":"Document type, required stages, official instructions…"},{"k":"notes","label":"2 — Discover the document","ph":"Situation, source, actors, event, tone…"},{"k":"essentials","label":"3 — Select and organise the essentials","ph":"The points the audience needs, grouped by function…"},{"k":"account","label":"4 — Prepare the required account / restitution","ph":"Faithful, structured, reformulated…"},{"k":"context","label":"5 — Add relevant context","ph":"Immediate event, broader debate, one or two connected facts…"},{"k":"issue","label":"6 — Identify the real issue","ph":"The conflict, contradiction or transformation…"},{"k":"question","label":"7 — Write the key question","ph":"One clear analytical question…"},{"k":"outline","label":"8 — Build the argument","ph":"Claim-based parts that answer the question…"},{"k":"examples","label":"9 — Verify and explain examples","ph":"Accurate evidence + analytical link…"},{"k":"delivery","label":"10 — Reduce notes for oral delivery","ph":"Keywords, pauses, pronunciation priorities…"},{"k":"interview","label":"11 — Prepare for interaction","ph":"Likely challenge, counterexample, clarification or limitation…"},{"k":"feedback","label":"12 — Turn feedback into the next action","ph":"One observable objective for class and the next colle…"}],"grid":["Format accuracy","Document comprehension","Selection and hierarchy","Faithful restitution","Relevant context","Identification of the issue","Key question","Analytical plan","Accuracy of examples","Explanation and links","English accuracy","Natural vocabulary","Pronunciation and delivery","Use of notes","Interaction","Response to feedback"]}},"help":[{"t":"checking my target format","mod":"m0"},{"t":"understanding jury expectations","mod":"m1"},{"t":"avoiding common jury-report traps","mod":"m2"},{"t":"reading efficiently","mod":"m3"},{"t":"understanding audio","mod":"m4"},{"t":"analysing video","mod":"m5"},{"t":"taking usable notes","mod":"m6"},{"t":"selecting essential information","mod":"m7"},{"t":"producing a faithful account","mod":"m8"},{"t":"separating restitution and commentary","mod":"m9"},{"t":"identifying the real issue","mod":"m10"},{"t":"contextualising","mod":"m11"},{"t":"finding the key question","mod":"m12"},{"t":"building an analytical plan","mod":"m13"},{"t":"choosing accurate examples","mod":"m14"},{"t":"developing an argument","mod":"m15"},{"t":"using civilisation knowledge","mod":"m16"},{"t":"writing introductions and conclusions","mod":"m17"},{"t":"speaking without reading","mod":"m18"},{"t":"handling questions and feedback","mod":"m19"}]};
